QUnit.module("$.bsCalendar.utils",function(){const u=$.bsCalendar.utils;QUnit.module("isValueEmpty",function(){QUnit.test("empty string → true",function(assert){assert.ok(u.isValueEmpty(""))});QUnit.test("null → true",function(assert){assert.ok(u.isValueEmpty(null))});QUnit.test("undefined → true",function(assert){assert.ok(u.isValueEmpty(undefined))});QUnit.test("non-empty string → false",function(assert){assert.notOk(u.isValueEmpty("hello"))});QUnit.test("zero → false",function(assert){assert.notOk(u.isValueEmpty(0))});QUnit.test("false → false",function(assert){assert.notOk(u.isValueEmpty(false))});QUnit.test("empty object → true",function(assert){assert.ok(u.isValueEmpty({}))});QUnit.test("non-empty object → false",function(assert){assert.notOk(u.isValueEmpty({a:1}))})});QUnit.module("getLanguageAndCountry",function(){QUnit.test('parses "de-DE" correctly',function(assert){const r=u.getLanguageAndCountry("de-DE");assert.strictEqual(r.language,"de");assert.strictEqual(r.country,"DE")});QUnit.test('parses "en-GB" correctly',function(assert){const r=u.getLanguageAndCountry("en-GB");assert.strictEqual(r.language,"en");assert.strictEqual(r.country,"GB")});QUnit.test("handles locale without region",function(assert){const r=u.getLanguageAndCountry("en");assert.strictEqual(r.language,"en")});QUnit.test('normalizes underscore variant "de_DE"',function(assert){const r=u.getLanguageAndCountry("de_DE");assert.strictEqual(r.language,"de");assert.strictEqual(r.country,"DE")})});QUnit.module("parseDateInput",function(){QUnit.test('parses "YYYY-MM-DD HH:mm:ss" string',function(assert){const d=u.parseDateInput("2026-05-08 10:30:00");assert.ok(d instanceof Date,"returns a Date");assert.strictEqual(d.getFullYear(),2026);assert.strictEqual(d.getMonth(),4);assert.strictEqual(d.getDate(),8);assert.strictEqual(d.getHours(),10);assert.strictEqual(d.getMinutes(),30)});QUnit.test('parses "YYYY-MM-DD" date-only string',function(assert){const d=u.parseDateInput("2026-01-15");assert.ok(d instanceof Date);assert.strictEqual(d.getFullYear(),2026);assert.strictEqual(d.getDate(),15)});QUnit.test("returns a Date unchanged when passed a Date",function(assert){const input=new Date(2026,4,8);const d=u.parseDateInput(input);assert.ok(d instanceof Date);assert.strictEqual(d.getFullYear(),2026)})});QUnit.module("normalizeDateTime",function(){QUnit.test('normalizes "YYYY-MM-DD HH:mm" to full format',function(assert){const result=u.normalizeDateTime("2026-05-08 10:30");assert.ok(typeof result==="string","returns a string");assert.ok(result.startsWith("2026-05-08"),"date part preserved")});QUnit.test('keeps "YYYY-MM-DD HH:mm:ss" unchanged',function(assert){const result=u.normalizeDateTime("2026-05-08 10:30:00");assert.ok(result.includes("10:30:00"))})});QUnit.module("formatDateToDateString",function(){QUnit.test('formats Date to "YYYY-MM-DD"',function(assert){const d=new Date(2026,4,8);assert.strictEqual(u.formatDateToDateString(d),"2026-05-08")});QUnit.test("pads month and day with zeros",function(assert){const d=new Date(2026,0,3);assert.strictEqual(u.formatDateToDateString(d),"2026-01-03")})});QUnit.module("formatTime",function(){QUnit.test('formats Date to "HH:MM:SS" by default',function(assert){const d=new Date(2026,0,1,9,5,3);const t=u.formatTime(d);assert.ok(/^\d{2}:\d{2}:\d{2}$/.test(t),`"${t}" matches HH:MM:SS`);assert.strictEqual(t,"09:05:03")});QUnit.test("formats without seconds when withSeconds=false",function(assert){const d=new Date(2026,0,1,14,30,0);const t=u.formatTime(d,false);assert.ok(/^\d{2}:\d{2}$/.test(t),`"${t}" matches HH:MM`)})});QUnit.module("getCalendarWeek",function(){QUnit.test("returns correct ISO week for Jan 5, 2026 (week 2)",function(assert){assert.strictEqual(u.getCalendarWeek(new Date(2026,0,5)),2)});QUnit.test("returns 1 for Jan 1, 2026 (Thursday, ISO week 1)",function(assert){assert.strictEqual(u.getCalendarWeek(new Date(2026,0,1)),1)})});QUnit.module("getShortWeekDayNames",function(){QUnit.test("returns 7 entries",function(assert){const names=u.getShortWeekDayNames("en-GB",false);assert.strictEqual(names.length,7)});QUnit.test("starts on Monday when startWeekOnSunday=false",function(assert){const names=u.getShortWeekDayNames("en-GB",false);const firstDay=new Intl.DateTimeFormat("en-GB",{weekday:"short"}).format(new Date(2026,0,5));assert.strictEqual(names[0],firstDay)});QUnit.test("starts on Sunday when startWeekOnSunday=true",function(assert){const names=u.getShortWeekDayNames("en-GB",true);const sunday=new Intl.DateTimeFormat("en-GB",{weekday:"short"}).format(new Date(2026,0,4));assert.strictEqual(names[0],sunday)})});QUnit.module("datesAreEqual",function(){QUnit.test("same day → true",function(assert){assert.ok(u.datesAreEqual(new Date(2026,4,8,9,0),new Date(2026,4,8,17,0)))});QUnit.test("different day → false",function(assert){assert.notOk(u.datesAreEqual(new Date(2026,4,8),new Date(2026,4,9)))})});QUnit.module("generateRandomString",function(){QUnit.test("returns a non-empty string",function(assert){const s=u.generateRandomString(8);assert.ok(typeof s==="string"&&s.length>0)});QUnit.test("two calls return different strings",function(assert){const a=u.generateRandomString(8);const b=u.generateRandomString(8);assert.notEqual(a,b)})});QUnit.module("isDarkColor",function(){QUnit.test("black → true",function(assert){assert.ok(u.isDarkColor("#000000"))});QUnit.test("white → false",function(assert){assert.notOk(u.isDarkColor("#ffffff"))});QUnit.test("dark navy → true",function(assert){assert.ok(u.isDarkColor("#001f3f"))});QUnit.test("bright yellow → false",function(assert){assert.notOk(u.isDarkColor("#ffff00"))})});QUnit.module("toHex",function(){QUnit.test('converts "rgb(255, 0, 0)" → "#ff0000"',function(assert){assert.strictEqual(u.toHex("rgb(255, 0, 0)"),"#ff0000")});QUnit.test("passes through existing hex value",function(assert){assert.strictEqual(u.toHex("#ff5733"),"#ff5733")})});QUnit.module("isDirectColorValid",function(){QUnit.test("valid hex → true",function(assert){assert.ok(u.isDirectColorValid("#ff5733"))});QUnit.test("valid rgb → true",function(assert){assert.ok(u.isDirectColorValid("rgb(255, 87, 51)"))});QUnit.test("Bootstrap class name → false",function(assert){assert.notOk(u.isDirectColorValid("primary"))})});QUnit.module("colorNameToHex",function(){QUnit.test("is a lookup object",function(assert){assert.strictEqual(typeof u.colorNameToHex,"object")});QUnit.test('resolves "red"',function(assert){assert.strictEqual(u.colorNameToHex.red,"#ff0000")});QUnit.test('resolves "steelblue"',function(assert){assert.ok(typeof u.colorNameToHex.steelblue==="string")})});QUnit.module("getColors",function(){QUnit.test("returns object with expected keys",function(assert){const c=u.getColors("#ff5733");assert.ok("origin"in c);assert.ok("backgroundColor"in c);assert.ok("color"in c)});QUnit.test("origin matches input",function(assert){const c=u.getColors("#ff5733");assert.strictEqual(c.origin,"#ff5733")});QUnit.test("fallback color used when primary is null",function(assert){const c=u.getColors(null,"primary");assert.ok(c!==null)})});QUnit.module("convertIcsToAppointments",function(){const MINIMAL_ICS=["BEGIN:VCALENDAR","VERSION:2.0","BEGIN:VEVENT","UID:test-uid-001","SUMMARY:Test Event","DTSTART:20260508T100000","DTEND:20260508T110000","END:VEVENT","END:VCALENDAR"].join("\r\n");QUnit.test("parses a minimal ICS string into one appointment",function(assert){const result=u.convertIcsToAppointments(MINIMAL_ICS);assert.strictEqual(result.length,1)});QUnit.test("maps SUMMARY to title",function(assert){const result=u.convertIcsToAppointments(MINIMAL_ICS);assert.strictEqual(result[0].title,"Test Event")});QUnit.test("maps UID to id",function(assert){const result=u.convertIcsToAppointments(MINIMAL_ICS);assert.strictEqual(result[0].id,"test-uid-001")});QUnit.test("parses start date correctly",function(assert){const result=u.convertIcsToAppointments(MINIMAL_ICS);assert.ok(result[0].start.startsWith("2026-05-08"))});QUnit.test("parses all-day events",function(assert){const allDayIcs=["BEGIN:VCALENDAR","BEGIN:VEVENT","SUMMARY:Holiday","DTSTART:20260508","DTEND:20260509","END:VEVENT","END:VCALENDAR"].join("\r\n");const result=u.convertIcsToAppointments(allDayIcs);assert.ok(result[0].allDay)});QUnit.test("returns empty array for empty string",function(assert){assert.deepEqual(u.convertIcsToAppointments(""),[])})})});